<template>
	<u-popup v-model="popupShow" mode="center" :mask-custom-style="{background: 'rgba(0, 0, 0, 0.1)'}"
		:border-radius="20" width="600rpx" :closeable="true" :z-index="100" @close="close" @open="open">
		<view class="popup-content">
			<view style="width: 500rpx;">
				<u-parse :html="form.tip" v-if="form.tip" :selectable="true" :show-with-animation="true"></u-parse>
				<u-form :labelWidth="140">
					<u-form-item label="账号" v-if="form.account">
						<view style="line-height: 34rpx;word-break:break-all" @click="handelCopyText(form.account)">
							{{form.account}}
							<u-icon style="margin-left: 4px;" name="zhuanfa" :size="30" color="rgb(94,94,94)"></u-icon>
						</view>
					</u-form-item>
					<u-form-item label="姓名" v-if="form.true_name">
						<view style="line-height: 34rpx;word-break:break-all" @click="handelCopyText(form.true_name)">
							{{form.true_name}}<u-icon style="margin-left: 4px;" name="zhuanfa" :size="30"
								color="rgb(94,94,94)"></u-icon>
						</view>
					</u-form-item>
					<template v-if="moneyType == 0">
						<u-form-item label="二维码" v-if="form.img">
							<u-image :src="form.img" :width="100" :height="100"
								@click="handelGoodsImgClick(form.img)"></u-image>
						</u-form-item>
						<u-form-item label="付款金额">
							<text style="color: red"> {{ form.total_price }}</text> 元
						</u-form-item>
					</template>
					<template v-else>
						<u-form-item label="付款金额">
							<money-list :list="form.pay_list" />
						</u-form-item>
					</template>
					<template v-if="form.is_trade_sn">
						<u-form-item label="订单号"><u-input placeholder="请输入订单号" v-model="form.trade_sn" /></u-form-item>
						<u-form-item :border-bottom="false">
							<view class="btn bg-blue" style="width: 100%;" @click="$u.throttle(ok, 1000)">确认支付</view>
						</u-form-item>
					</template>
				</u-form>
			</view>
		</view>
	</u-popup>

</template>

<script>
	import MoneyList from './MoneyList'
	export default {
		components: {
			'money-list': MoneyList
		},
		props: {
			show: {
				type: Boolean,
				default: false,
			},
			source: {
				type: Object,
				default: () => {}
			},
		},
		data() {
			return {
				popupShow: false,
				form: {},
			}
		},
		computed: {
			moneyType() {
				if (Reflect.has(this.form, 'pay_list')) return 1
				else return 0
			}
		},
		watch: {
			show(nv) {
				this.popupShow = nv
			},
			source: {
				handler(nv) {
					this.form = nv
				},
				deep: true,
			},
		},
		methods: {
			open() {},
			close() {
				this.$emit('update:show', false)
			},
			// 转账加款-确认支付
			async ok() {
				if (!this.form.trade_sn) {
					this.$util.msg('请输入订单号');
					return
				}

				const {
					status,
					url
				} = await this.$u.api.payStatus({
					order_sn: this.form.order_sn,
					trade_sn: this.form.trade_sn,
					pay_id: this.form.pay_id
				})
				if (status == 1) {
					this.$util.msg('支付成功')
					this.$emit('pay-ok', {
						url
					})

				} else {
					this.$util.msg('订单未支付')
				}

			},
			// 图片预览
			handelGoodsImgClick(url) {
				uni.previewImage({
					urls: [url],
					current: 0
				})
			},
			// 复制文本
			handelCopyText(txt) {
				uni.setClipboardData({
					data: txt,
					success() {
						uni.showToast({
							title: '复制成功',
							icon: 'success'
						});
					},
					fail() {
						uni.showToast({
							title: '复制失败',
							icon: 'none'
						});
					}
				});
			},
		},
	}
</script>

<style lang="scss" scoped scoped>
	.popup-content {
		display: flex;
		align-items: center;
		padding: 40rpx;
		flex-direction: column;
		gap: 20rpx;

		&>.title {
			font-weight: bolder;
			font-size: 30rpx;
		}
	}
</style>