<template>
	<view class="page">
		<u-navbar :is-back="false" :z-index="10">
			<template v-slot:default>
				<view style="width: 100%;">
					<!-- 充值方式 -->
					<u-tabs :list="rechargeType" :is-scroll="false" :current="currentRechargeTypeIndex"
						active-color="#F00704" inactive-color="#666666" :bold="false"
						@change="rechargeTypeChange"></u-tabs>
				</view>
			</template>
		</u-navbar>
		<!-- 一级，二级联动 -->
		<capsule-tabs ref="capsule-tabs" :list="categoryList" :currentCate="currentCate" :goodsList="goodsList"
			:currGoods="currGoods" @cate-change="cateChange" @goods-selected="goodsSelected"
			@order-tpl="orderTplChange">
		</capsule-tabs>

		<!-- 购买 -->
		<view class="buy-box">
			<u-button shape="circle" type="error" @click="handelBuy">购买</u-button>
		</view>

		<!-- 分享 -->
		<view class="share-box" v-if="currentRechargeTypeData">
			<!-- <view class="share-item">
				<u-image :src="require(`@/static/img/tag1.png`)" width="30" height="30" />
				<view>价格反馈</view>
			</view> -->
			<view class="share-item" v-if="currentRechargeTypeData.kefu"
				@click="$util.on(currentRechargeTypeData.kefu_link)">
				<u-image :src="require(`@/static/img/service2.png`)" width="30" height="30" />
				<view>联系客服</view>
			</view>
			<view class="share-item" v-if="currentRechargeTypeData.fenxiang" @click="doShare">
				<u-image :src="require(`@/static/img/tag2.png`)" width="30" height="30" />
				<view>分享</view>
			</view>
		</view>

		<!-- 说明详情 -->
		<view class="detail-box" v-if="currentRechargeTypeData && currentRechargeTypeData.describe">
			<view class="wrap">
				<u-parse :html="currentRechargeTypeData.describe"></u-parse>
			</view>
		</view>

		<view class="footer">
			<view class="pop-box" v-if="currGoods && currGoods.is_pop">
				<view class="pop-wrap" @click="showGoodsTipPopup=true">
					<u-tag text="重要提示" type="error" mode="dark" />
					<view class="txt line1">
						{{currGoods.recharge_sku_info_titel}}
					</view>
					<view class="show-btn">查看</view>
				</view>
			</view>
		</view>
		<!-- <product-win v-model="showBuyPopup" /> -->
		<!-- 支付弹框-start -->
		<pay-way-popup v-model="showPayWayPopup" :ordersn="ordersn" @success="paySuccess" />
		<!-- 支付弹框-end -->
		<!-- 商品提示弹框 -->
		<goods-tip-popup v-model="showGoodsTipPopup" :content="currGoods && currGoods.recharge_sku_info" />
	</view>
</template>

<script>
	import CapsuleTabs from './components/capsule-tabs'
	// import ProductWin from './components/product-win'
	import _ from 'lodash'
	import PayWayPopup from '@/components/pay-way/popup'
	import GoodsTipPopup from './components/goods-tip-popup'
	import {
		mapGetters
	} from 'vuex'

	export default {
		name: 'FastRecharge',
		components: {
			CapsuleTabs,
			// ProductWin,
			PayWayPopup,
			'goods-tip-popup': GoodsTipPopup,
		},
		provide() {
			return {
				inputSuffixIcon: () => {
					return this.currentCate[1] ? this.currentCate[1].img : ''
				}
			};
		},
		data() {
			return {
				rechargeTypeList: [],
				queryForm: {
					cate_type: '', // 目录类型'
				},
				currentRechargeTypeIndex: 0,

				categoryList: [], // 分类树数据
				currentCate: [], // 当前分类列表
				goodsList: [], // 商品列表
				currGoods: null, // 选中的商品

				// 购买弹窗
				// showBuyPopup: false,

				// 选择支付方式弹窗
				showPayWayPopup: false,
				ordersn: '', // 订单号
				// 创建快速充值订单
				orderForm: {
					batch_tpl: '',
					recharge_sku_id: ''
				},

				showGoodsTipPopup: false,
				popupedGoods: [],
			}
		},
		computed: {
			...mapGetters(['userinfo']),
			rechargeType() {
				return this.rechargeTypeList.map(item => {
					return {
						name: item.name,
						value: item.quick_type,
						icon: this.$util.img2(item.img),
						link: item.jump_value
					}
				})
			},
			currentRechargeType() {
				return this.rechargeTypeList[this.currentRechargeTypeIndex].quick_type
			},
			currentRechargeTypeData() {
				return this.rechargeTypeList[this.currentRechargeTypeIndex]
			},
			payMoney() {
				if (this.currGoods) {
					return {
						'now_price': this.currGoods.price,
						'old_price': this.currGoods.face_value
					}
				} else
					return null
			},
		},
		watch: {
			currGoods(newValue, oldValue) {
				if (newValue) {
					const arr = [...this.popupedGoods, newValue.id]
					const set = new Set(arr)
					this.popupedGoods = [...set]
				}
			},
			sysconfig(nv) {
				if (nv && nv.addon && nv.addon.categoryrecharge) {
					if (_.isEmpty(this.rechargeTypeList)) {
						this.init()
					}
				} else {
					this.$util.back()
				}
			},
		},
		onLoad() {
			if (this.sysconfig.addon && this.sysconfig.addon.categoryrecharge) {
				this.init()
			}
		},
		methods: {
			async init() {
				this.rechargeTypeList = await this.$u.api.fastRechargeConfig()
				if (_.isEmpty(this.rechargeTypeList)) {
					this.$util.msg('数据为空')
					return
				}
				if (this.rechargeTypeList[0].jump_value) {
					this.$util.on(this.rechargeTypeList[0].jump_value)
					return
				} else {
					this.queryForm.cate_type = this.rechargeTypeList[0] ? this.rechargeTypeList[0].quick_type : ''
				}

				const {
					type,
					cpid, // 一级分类id
					cid, // 二级分类id
					cgid, // 三级分类id
					gid, // 商品id
				} = this.$Route.query
				this.initType(type)
				await this.fetchData()
				this.currentCate = this.initCategoryData(this.categoryList, [cpid, cid, cgid])
				this.loadRechargeGoods(gid)
			},
			async fetchData() {
				const data = await this.$u.api.categoryRecharge(this.queryForm)
				this.categoryList = data.category_list
			},
			initType(type) {
				let ids = this.rechargeType.map(item => item.value)
				if (!ids.includes(Number(type)))
					return
				this.queryForm.cate_type = type
				this.currentRechargeTypeIndex = ids.findIndex(id => id == type)
			},
			initCategoryData(nodes, path, result = []) {
				const id = path.shift()
				if (id) {
					const node = nodes.find(item => item.id == id)
					if (node.id == id) {
						result.push(node)

						if (node.children) {
							this.initCategoryData(node.children, path, result)
						}
					} else {
						if (node.children) {
							this.initCategoryData(node.children, path, result)
						}
					}
				} else {
					if (nodes.length) {
						result.push(nodes[0])
						if (nodes[0].children) {
							this.initCategoryData(nodes[0].children, path, result)
						}
					}
				}

				return result
			},
			async loadRechargeGoods(gid) {
				const jump_var = this.currentCate.map(item => item.id)
				const currCategory = this.$util.findItemByIdPath(this.categoryList, jump_var)

				if (!currCategory) {
					this.goodsList = []
					this.currGoods = null
					return
				}

				const data = await this.$u.api.categoryRechargeGoods({
					pcate_id: currCategory.id
				})
				this.goodsList = data
				if (data.length) {
					if (gid) {
						this.currGoods = this.goodsList.find(item => item.id == gid)
					} else {
						this.currGoods = data[0]
					}
					if (this.currGoods.is_pop && !this.popupedGoods.includes(this.currGoods.id)) {
						this.showGoodsTipPopup = true
					}
				} else
					this.currGoods = null
			},
			rechargeTypeChange(e) {
				const type = this.rechargeTypeList[e]
				if (type.jump_value) {
					this.$util.on(type.jump_value)
					return
				}

				this.currentRechargeTypeIndex = e
				this.queryForm.cate_type = this.currentRechargeType
				this.fetchData().then(() => {
					this.currentCate = this.initCategoryData(this.categoryList, [])
					this.loadRechargeGoods()
				})
			},
			cateChange(e) {
				this.currentCate = e
				this.loadRechargeGoods()
			},
			goodsSelected(e) {
				this.currGoods = e
				if (e.is_pop && !this.popupedGoods.includes(e.id)) {
					this.showGoodsTipPopup = true
				}
			},
			orderTplChange(e) {
				this.orderForm = Object.assign(this.orderForm, e)
			},
			// 点击购买
			handelBuy: _.throttle(async function() {
				if (!this.currGoods) {
					this.$util.msg('商品数据不存在！')
					return
				}
				this.orderForm.recharge_sku_id = this.currGoods.id
				await this.$refs['capsule-tabs'].checkForm()
				const ordersn = await this.createOrder()

				this.ordersn = ordersn
				this.showPayWayPopup = true
			}, 1000),
			async createOrder() {
				const {
					order_sn
				} = await this.$u.api.pollingOrder(this.orderForm)
				return order_sn
			},
			doShare() {
				const [cpid, cid, cgid] = this.currentCate.map(item => item.id)
				let shareLink = ''
				// #ifdef H5
				shareLink = this.$util.getShareLink2({
					type: this.currentRechargeType,
					pid: this.userinfo.id,
					cpid,
					cid,
					cgid,
					gid: this.currGoods.id
				})
				uni.setClipboardData({
					data: shareLink,
					success: function() {
						uni.showToast({
							title: '复制成功,请前往分享',
							mask: false,
							duration: 1500,
							icon: 'none'
						});
					}
				})
				// #endif				
			},
			// 支付成功回调
			paySuccess(e) {
				if (!this.sysconfig.change_site_info) {

					const {
						orderData
					} = e
					this.$util.on('/pages/order/info?id=' + orderData.order_id);

				} else {
					uni.setStorage({
						key: 'bangOrderInfo',
						data: JSON.stringify(this.order)
					});
					this.$util.on('/pages/order/bang?pid=' + this.userinfo.id);
				}
			}
		}
	}
</script>

<style lang="scss" scoped scoped>
	::v-deep {
		.u-tabs {
			position: relative;
			z-index: 6;
		}
	}

	.page {
		background: #fff;
		height: 100% !important;
	}

	.order-tpl-box {
		background-color: gray;
		min-height: 200rpx;
		margin: 40px;
	}

	.buy-box {
		padding: 0px 15px;
		margin-top: 21px;
	}

	.share-box {
		padding: 0px 30rpx;
		margin-top: 42rpx;
		display: flex;
		justify-content: space-between;
		font-size: 30rpx;
		color: rgb(248, 87, 48);
		line-height: 40rpx;

		.share-item {
			display: flex;
			gap: 10rpx;
			align-items: center;
		}
	}

	.detail-box {
		padding: 0px 36rpx;
		margin-top: 30rpx;

		.wrap {
			background-color: rgb(255, 245, 235);
			border-radius: 10px;
			padding: 20px 20px 10px 18px;
		}
	}

	.footer {
		padding-top: 140rpx;
		/* 兼容 iOS < 11.2 */
		padding-bottom: constant(safe-area-inset-bottom);
		/* 兼容 iOS >= 11.2 */
		padding-bottom: env(safe-area-inset-bottom);

		.pop-box {
			position: fixed;
			left: 0;
			bottom: 0rpx;
			right: 0;
			z-index: 4;
			padding: 20rpx;
			background-color: #FFEBEB;

			.pop-wrap {
				display: flex;
				align-items: center;
				justify-content: space-between;

				.txt {
					flex: 1;
					overflow: hidden;
					margin: 0 10rpx;
				}

				.show-btn {
					color: #FE4749;
				}
			}
		}

		.fixed-box {
			position: fixed;
			bottom: 0;
			left: 0;
			right: 0;
			z-index: 4;
			padding: 20rpx;
		}
	}

	body {
		margin-bottom: constant(safe-area-inset-bottom) !important;
		margin-bottom: env(safe-area-inset-bottom) !important;

		#toolbar,
		#bottombar {
			display: none !important;
		}
	}
</style>