<template>
	<view class="comp-box">
		<!-- 遮罩层 -->
		<view class="mask" v-show="showMask" @click="showMask = false" @touchmove.stop.prevent></view>
		<view class="cate-box" @touchmove.stop.prevent>
			<!-- 一级 -->
			<scroll-view class="scroll-view_H cate-1" scroll-x="true" :scroll-into-view="scrollId"
				scroll-with-animation>
				<view :id="`id-${item.id}`" class="scroll-view-item_H cate-1-item"
					:class="{active:item.id === currOneCate.id}" v-for="(item,index) in oneCateList"
					@click="oneCateChange(item,index)" :key="index">
					{{item.name}}
				</view>
			</scroll-view>
			<!-- 二级 -->
			<scroll-view :scroll-top="0" scroll-y="true" class="scroll-Y">
				<view class="scroll-view-item chong-box">
					<view class="chong-item" :class="{active:item.id === currTwoCate.id}"
						v-for="(item,index) in shortTwoCateList" :key="index" @click="twoCateChange(item,index)">
						<view class="item-wrap">
							<u-image width="60" height="60" :src="$util.img(item.img)" />
							<view class="name line1">{{item.name}}</view>
						</view>
					</view>
				</view>
			</scroll-view>
			<view class="more-btn" @click="showMask = !showMask" v-if="twoCateList && twoCateList.length > 4">
				<image class="img" mode="aspectFit" :src="require('static/img/down.png')" v-if="!showMask" />
				<image class="img" mode="aspectFit" :src="require('static/img/up.png')" v-else />
			</view>
		</view>
		<!-- 下单模板 -->
		<view class="product-tpl" v-if="currGoods && currGoods.order_tpl && currGoods.order_tpl.length">
			<goods-attach ref="attach" :attach="currGoods.order_tpl" :show-batch-order="false"
				@attach-value="getAttachValue" />
		</view>
		<!-- 三级分类 -->
		<scroll-view class="scroll-view_H cate-3" scroll-x="true" v-if="threeCateList.length">
			<view class="scroll-view-item_H cate-3-item" :class="{active:item.id === currThreeCate.id}"
				v-for="(item,index) in threeCateList" :key="index" @click="threeCateChange(item,index)">
				<view class="item-wrap">
					<view class="name">{{item.name}}</view>
					<view class="mark line2">{{item.short_name}}</view>
				</view>
			</view>
		</scroll-view>
		<!-- 商品 -->
		<view class="goods-box">
			<view class="goods-item" :class="{active:item.id === currGoods.id}" v-for="(item,index) in goodsList"
				:key="index" @click="handelGoodsClick(item,index)">
				<view class="item-wrap">
					<view class="top">
						<view class="name line1">{{item.name}}</view>
						<view class="price">
							<price-symbol :now-price="item.price" :showOldPrice="false" />
						</view>
						<view class="old-price">
							<price-symbol :oldPrice="item.face_value" :showNowPrice="false" />
						</view>
					</view>
					<!-- <view class="time">耗时：{{item.order_time}}</view> -->
				</view>
			</view>
		</view>
	</view>
</template>

<script>
	import PriceSymbol from '@/components/price-symbol'
	import Attach from '@/components/ChooseOrderTplDialog/attach_fast_recharge'

	export default {
		components: {
			PriceSymbol,
			'goods-attach': Attach,
		},
		props: {
			// 分类树数据
			list: {
				type: Array,
				default: () => []
			},
			// 默认选中的分类
			currentCate: {
				type: Array,
				default: () => []
			},
			// 选中分类下的商品列表
			goodsList: {
				type: Array,
				default: () => []
			},
			// 选中的商品
			currGoods: {
				type: Object,
				default: () => ({})
			}
		},
		data() {
			return {
				scrollId: '',
				showMask: false,

				twoCateIndex: 0,
			}
		},
		computed: {
			// 只负责展示一级分类列表
			oneCateList() {
				return [...this.list]
			},
			currOneCate() {
				if (this.currentCate && this.currentCate[0])
					return this.currentCate[0]
				else
					return {}
			},
			twoCateList() {
				if (this.currOneCate.children)
					return this.currOneCate.children
				else
					return []
			},
			shortTwoCateList() {
				if (this.twoCateList.length > 4) {
					if (this.showMask)
						return this.twoCateList
					else
						return this.twoCateList.slice(0, 4)
				} else {
					return this.twoCateList
				}
			},
			currTwoCate() {
				if (this.currentCate && this.currentCate[1])
					return this.currentCate[1]
				else
					return {}
			},
			threeCateList() {
				if (this.currTwoCate.children)
					return this.currTwoCate.children
				else
					return []
			},
			currThreeCate() {
				if (this.currentCate && this.currentCate[2])
					return this.currentCate[2]
				else
					return {}
			},
		},
		watch: {
			currentCate(nv) {
				let id = this.currOneCate.id
				if (id)
					this.scrollId = "id-" + id.toString()
			},
		},
		mounted() {

		},
		methods: {
			// 一级改变事件
			oneCateChange(item, index) {
				this.showMask = false
				this.$emit('cate-change', this.initCategoryData(this.list, item.jump_var.split(',')))
			},
			// 二级改变事件
			twoCateChange(item, index) {
				this.showMask = false
				if (index > 3) {
					// currentCate是prpo属性
					this.currentCate[0].children = this.$util.exchangeArray(index, this.twoCateIndex, this.twoCateList,
						true)
				} else {
					this.twoCateIndex = index
				}
				this.$emit('cate-change', this.initCategoryData(this.list, item.jump_var.split(',')))
			},
			// 三级改变事件
			threeCateChange(item, index) {
				this.$emit('cate-change', this.initCategoryData(this.list, item.jump_var.split(',')))
			},
			initCategoryData(nodes, path, result = []) {
				const id = path.shift()
				if (id) {
					const node = nodes.find(item => item.id == id)
					if (node.id == id) {
						result.push(node)

						if (node.children) {
							this.initCategoryData(node.children, path, result)
						}
					} else {
						if (node.children) {
							this.initCategoryData(node.children, path, result)
						}
					}
				} else {
					if (nodes.length) {
						result.push(nodes[0])
						if (nodes[0].children) {
							this.initCategoryData(nodes[0].children, path, result)
						}
					}
				}

				return result
			},
			handelGoodsClick(item, index) {
				if (this.currGoods.id !== item.id)
					this.$emit('goods-selected', item)
			},
			getAttachValue({
				batch_tpl
			}) {
				this.$emit('order-tpl', {
					batch_tpl
				})
			},
			async checkForm() {
				return this.$refs['attach'].checkForm()
			},
		},
	}
</script>

<style lang="scss" scoped scoped>
	.comp-box {}

	.mask {
		background-color: rgba(0, 0, 0, .3);
		// background-color: hsla(0, 0%, 100%, .9);
	}

	.cate-box {
		position: relative;
		z-index: 6;
		background-color: rgb(254, 240, 227);
		border-radius: 0px 0px 32rpx 32rpx;
		padding-bottom: 20rpx;
	}

	.scroll-view_H {
		white-space: nowrap;
		width: 100%;

		.scroll-view-item_H {
			display: inline-block;
			background: #fff;
			color: #7f5534;
			font-size: 28rpx;
			vertical-align: bottom;

			&+.scroll-view-item_H {
				margin-left: 20rpx;
			}

			&:first-child {
				margin-left: 20rpx;
			}

			&:last-child {
				margin-right: 20rpx;
			}
		}
	}

	.cate-1 {
		padding: 28rpx 0;

		.cate-1-item {
			border-radius: 60rpx;
			padding: 10rpx 24rpx;
		}

		.active {
			color: #fff;
			background: #f00704;
		}
	}


	.scroll-Y {
		max-height: calc(100vh - 400rpx);

		.chong-box {
			display: grid;
			grid-template-columns: repeat(4, 1fr);
			gap: 20rpx;
			padding: 0 20rpx;

			.chong-item {
				width: 100%;
				overflow: hidden;

				.item-wrap {
					border: 2rpx solid #fff;
					display: flex;
					flex-direction: column;
					justify-content: center;
					align-items: center;
					overflow: hidden;
					height: 190rpx;
					padding: 30rpx 0 24rpx;
					font-size: 24rpx;
					text-align: center;
					cursor: pointer;
					background-color: #fff;
					border-radius: 30rpx;
					box-shadow: 0 4rpx 10rpx rgba(0, 0, 0, .05);

					.name {
						margin-top: 20rpx;
						width: 100%;
						font-weight: 700;
						padding: 0 20rpx;
					}

					.info {
						color: #666;

						.price {
							color: #f4353d;
						}
					}
				}
			}

			.active {
				.item-wrap {
					border: 1px solid #f00704;
				}
			}

		}
	}

	.more-btn {
		display: flex;
		justify-content: center;
		margin-top: 20rpx;

		.img {
			height: 20rpx;
			opacity: .75;
		}
	}

	.product-tpl {}

	.cate-3 {
		margin-top: 40rpx;

		.cate-3-item {
			width: 30%;
			border-radius: 10rpx;
			border: 2rpx solid #efedec;
			background: url(@/static/img/noactive-vip.png) 100% 100% no-repeat;
			background-size: auto 80%;
			padding: 16rpx 20rpx;
			height: 152rpx;
			color: rgb(102, 102, 102);
			font-size: 26rpx;

			.item-wrap {
				width: 100%;

				.name {
					font-weight: 700;
				}

				.mark {
					color: rgb(153, 153, 153);
					font-size: 24rpx;
					white-space: normal;
				}
			}

			&:first-child {
				margin-left: 36rpx;
			}

			&:last-child {
				margin-right: 36rpx;
			}
		}

		.active {
			color: #fff;
			border: 1px solid #fe3f3e;
			background: #fe3f3e url(@/static/img/active-vip.png) 100% 100% no-repeat;
			background-size: auto 80%;

			.item-wrap {
				.mark {
					color: #fff;
				}
			}

		}
	}

	.goods-box {
		display: grid;
		grid-template-columns: repeat(3, 1fr);
		gap: 20rpx;
		padding: 0 36rpx;
		margin-top: 36rpx;

		.goods-item {
			width: 100%;
			overflow: hidden;

			.item-wrap {
				width: 100%;
				height: 100%;
				display: flex;
				flex-direction: column;
				align-items: center;
				justify-content: center;
				height: 200rpx;
				border-radius: 12rpx;
				border: 1px solid #eaeaec;
				gap: 10rpx;
				line-height: normal;
				background-color: #FEF3F0;

				.top {
					flex: 1;
					display: flex;
					flex-direction: column;
					justify-content: center;
					align-items: center;

					.name {
						color: #999;

					}

					.price {
						margin-top: 10rpx;
					}
				}

				.time {
					margin-top: 10rpx;
					margin-bottom: 10rpx;
					background: rgba(255, 222, 199, 0.74);
					border-radius: 30px;
					font-size: 22rpx;
					color: rgb(135, 81, 53);
					white-space: nowrap;
					padding: 4rpx 20rpx;
				}

			}
		}

		.active {
			.item-wrap {
				border: 1px solid #ef995d;
				// background-color: #fff5ee;
			}
		}
	}
</style>