<template>
	<view @touchmove.stop.prevent="stopRoll">
		<u-popup v-model="popupShow" mode="bottom" :z-index="12" :custom-style="customStyle"
			:mask-custom-style="{background: 'rgba(0, 0, 0, 0.4)'}" :border-radius="20" :closeable="true"
			close-icon-color="#333" height="60%" @close="close" @open="open">
			<view class="popup-box">
				<view class="popup-title">选择支付</view>
				<scroll-view scroll-y="true" class="scroll-Y" @scrolltoupper="upper" @scrolltolower="lower"
					@scroll="scroll">
					<pay-way ref="pay-way" type="pay" :orderSn="ordersn" @change="handelPayWayChange" />
				</scroll-view>
				<view class="popup-footer">
					<view class="btn bg-red ok-btn" @click="handelOk">立即支付 <price-symbol v-if="orderData"
							:now-price="orderData.price" :showOldPrice="false" nowPriceColor="#fff" /></view>
				</view>
			</view>
		</u-popup>
		<password-input :popupShow.sync="showPassInput" @ok="handelPasswordInputOk" />
		<scanpay-qrcode-popup :qrcodeshow.sync="qrcodeshow" :title="payWay ? payWay.title:''" :qrcodeurl="qrcodeUrl"
			:copymark="copyMark" @close="handelScanpyQrcodeClose" />
		<alipayuser-popup :show.sync="alipayuserPopupShow" :source="alipayuserPopupData" @pay-ok="handelAlipayUserOk" />
		<payjun-popup :show.sync="payjunPopupShow" :source="alipayuserPopupData" @pay-ok="handelAlipayUserOk" />
		
		
	</view>
</template>

<script>
	// 使用该组件前提必须有订单编号，即需要下单的支付场景
	import PayWay from './index.vue'
	import PriceSymbol from '@/components/price-symbol'
	import PasswordInput from '@/components/password-input/index'
	import ScanpayQrcodePopup from '@/components/scanpay-qrcode-popup'
	import AlipayUserPopup from '@/components/alipayuser-popup'
import PayjunPopup from '@/components/payjun-popup'
	export default {
		name: 'pay-way-popup',
		components: {
			PayWay,
			PriceSymbol,
			'password-input': PasswordInput,
			'scanpay-qrcode-popup': ScanpayQrcodePopup,
			'alipayuser-popup': AlipayUserPopup,
			'payjun-popup': PayjunPopup,
		},
		props: {
			customStyle: {
				type: Object,
				default: () => {}
			},
			value: {
				type: Boolean,
				default: false
			},
			ordersn: {
				type: String,
				required: true,
				default: ''
			},
		},
		data() {
			return {
				payWay: null, // 当前支付方式

				showPassInput: false, // 显示交易密码框

				alipayuserPopupShow: false, //显示转账加款弹框
					payjunPopupShow: false, //显示骏卡支付弹框
				alipayuserPopupData: {}, //弹框渲染的内容

				qrcodeshow: false, // 显示扫描支付弹框
				qrcodeUrl: '',
				copyMark: '',

				orderData: null,

				// 创建支付订单
				payForm: {
					ordersn: "",
					pay_type: "",
					pay_id: '',
					trade_password: "",
					money: "",
					wxpaycode: ""
				},
			}
		},
		computed: {
			popupShow: {
				get() {
					return this.value
				},
				set(val) {
					this.$emit('input', val ? true : false)
				}
			},
		},
		watch: {

		},
		mounted() {

		},
		methods: {
			stopRoll() {},
			close() {

			},
			open() {
				this.init()
			},
			async init() {
				this.orderData = await this.$u.api.payInfo({
					order_sn: this.ordersn
				})

			},
			scroll() {},
			handelPayWayChange(e) {
				this.payWay = e
			},
			lower() {},
			upper() {},
			handelOk() {
				if (!this.payWay) {
					this.$util.msg('请选择支付方式')
					return
				}
				// this.$emit('pay', this.payWay)
				this.doPay()
			},
			doPay: _.throttle(async function() {
				this.payForm.ordersn = this.ordersn
				this.payForm.pay_type = this.payWay.name
				this.payForm.pay_id = this.payWay.name == 'balance' ? '' : this.payWay.id

				if (this.payWay.name == 'balance') {
					if (this.payWay.need_trade_password && !this.payForm.trade_password) {
						this.showPassInput = true
					} else {
						this.pay()
					}
				} else {
					this.pay()
				}
			}, 1000),
			
			async pay() {
				try {
					var {
						url_type,
						url,
						order_sn,
						orderid,
						pay_data,
					} = await this.$u.api.pay(this.payForm)
				} catch (e) {
					this.payForm.trade_password = ''
					if (e.data.msg == "用户余额不足") {
						setTimeout(() => {
							this.$util.on('/pages/ucenter_sub/recharge');
						}, 1000)
					}
					return
				}
				this.clearInterval()
				if (this.payForm.pay_type == 'balance') {
					this.$util.msg('支付成功');
					setTimeout(() => {
						this.popupShow = false
						// this.$util.on('/pages/order/info?id=' + orderid);
						this.$emit('success', {
							payWay: this.payWay,
							orderData: this.orderData,
							payForm: this.payForm
						})
					}, 1000)
					return
				} else {
					this.paystatusTimer = setInterval(() => {
						this.paystatus()
					}, 2000)
				}
				let that = this
				switch (url_type) {
					case 1:
						this.qrcodeUrl = url

						//收款人身份
						if (this.payWay.name == 'alipayuser' && pay_data && pay_data.true_name) {
							this.copyMark = pay_data.true_name;
						} else {
							this.copyMark = '';
						}

						if (this.payWay.name == 'alipay' || this.payWay.name == 'alipayuser') {
							this.$util.openAppUrl(this.qrcodeUrl)
						}
						this.qrcodeshow = true

						break;
					case 2:
						//#ifdef MP-WEIXIN
						if (this.payWay.name == 'alipay') {
							this.qrcodeUrl = url
							this.qrcodeshow = true
						}
						//#endif
						//#ifdef H5
						window.location.href = url
						//#endif
						// #ifdef APP-PLUS
						this.qrcodeUrl = url
						this.qrcodeshow = true
						//#endif
						break;
					case 3:
						//#ifdef H5
						window.location.href = url
						//#endif
						break;
					case 4:
						//#ifdef H5
						jWeixin.config({
							debug: false, // 开启调试模式,调用的所有api的返回值会在客户端alert出来，若要查看传入的参数，可以在pc端打开，参数信息会通过log打出，仅在pc端时才会打印。
							appId: pay_data.appId, // 必填，公众号的唯一标识
							timestamp: pay_data.timeStamp, // 必填，生成签名的时间戳
							nonceStr: pay_data.nonceStr, // 必填，生成签名的随机串
							signature: pay_data.paySign, // 必填，签名
							jsApiList: [ //这里是需要用到的接口名称  
								'checkJsApi', //判断当前客户端版本是否支持指定JS接口  
								'onMenuShareAppMessage', //分享接口  
								'getLocation', //获取位置  
								'openLocation', //打开位置  
								'scanQRCode', //扫一扫接口  
								'chooseWXPay', //微信支付  
								'chooseImage', //拍照或从手机相册中选图接口  
								'previewImage', //预览图片接口  
								'uploadImage' //上传图片  
							], // 必填，需要使用的JS接口列表
							openId: this.userinfo.wxgzh_openid
						})
						//付款
						jWeixin.chooseWXPay({
							appId: pay_data.appId,
							timestamp: pay_data
								.timeStamp, // 支付签名时间戳，注意微信jssdk中的所有使用timestamp字段均为小写。但最新版的支付后台生成签名使用的timeStamp字段名需大写其中的S字符
							nonceStr: pay_data.nonceStr, // 支付签名随机串，不长于 32
							package: pay_data
								.package, // 统一支付接口返回的prepay_id参数值，提交格式如：prepay_id=\*\*\*）
							signType: pay_data.signType, // 签名方式，默认为'SHA1'，使用新版支付需传入'MD5'
							paySign: pay_data.paySign, // 支付签名
							success: function(res) {

							},
							cancel: function(res) {
								that.$util.msg('取消支付');
								this.clearInterval()
							},
							fail: function(res) {
								that.$util.msg('付款失败');
								this.clearInterval()
							}
						});
						//#endif
						break;
					case 5:
						// #ifdef MP
						let mp_pay_name = ''
						if (uni.requestOrderPayment) {
							mp_pay_name = 'requestOrderPayment'
						} else {
							mp_pay_name = 'requestPayment'
						}
						uni.showLoading({
							title: `支付中`
						})
						uni[mp_pay_name]({
							timeStamp: pay_data.timeStamp,
							nonceStr: pay_data.nonceStr,
							package: pay_data.package,
							signType: pay_data.signType,
							paySign: pay_data.paySign,
							success: function(res) {
								uni.hideLoading()
								that.$util.msg(res.msg)
							},
							fail: function(e) {
								uni.hideLoading();
								that.$util.msg('取消支付')
							},
							complete: function(e) {
								uni.hideLoading();
								if (e.errMsg == 'requestPayment:cancel' || e.errMsg ==
									'requestOrderPayment:cancel') return
								that.$util.msg('取消支付');
							},
						});
						// #endif
						break;
					case 6:
						// #ifdef APP-PLUS
						// console.log(res)
						uni.showLoading({
							mask: true,
							title: '支付中...'
						});
						uni.requestPayment({
							provider: 'wxpay',
							orderInfo: pay_data,
							success: (e) => {
								that.$util.msg(`支付成功`)
							},
							fail: (e) => {
								that.$util.msg(`支付失败`)
							},
							complete: () => {
								// 余额支付直接跳到订单详情
								// that.ordersn = ''
								// that.order_id = ''
								this.clearInterval()
								uni.hideLoading()
							},
						});
						// #endif
						break;
					case 7:
						// #ifdef APP-PLUS
						uni.showLoading({
							mask: true,
							title: '支付中...'
						});
						uni.requestPayment({
							provider: 'alipay',
							orderInfo: pay_data,
							success: (e) => {
								that.$util.msg(`支付成功`)
							},
							fail: (e) => {
								console.log(e)
								that.$util.msg(`支付失败`)
							},
							complete: (e) => {
								console.log(e)
								// 余额支付直接跳到订单详情
								// that.ordersn = ''
								// that.order_id = ''
								this.clearInterval()
								uni.hideLoading()
							},
						});
						// #endif
						break;
					case 8:
						this.alipayuserPopupData = {
							trade_sn: '',
							order_sn,
							pay_id: this.payForm.pay_id,
							...pay_data
						}
						if (this.alipayuserPopupData.is_trade_sn) {
							this.clearInterval()
						}
						if (this.alipayuserPopupData.is_need_account) {
							this.$util.msg('请使用支付宝提现账号付款')
							setTimeout(() => {
								this.$util.on('/pages/ucenter_sub/draw')
							}, 2000)
						} else
							this.alipayuserPopupShow = true
						break;
						
						case 9: //骏卡支付
							this.alipayuserPopupData = {
								trade_sn: '',
								order_sn,
								pay_id: this.payForm.pay_id,
								...pay_data
							}
						
							this.payjunPopupShow = true
							break;
					default:
						break;
				}
			},
			async paystatus() {
				try {
					const {
						status,
						url
					} = await this.$u.api.payStatus({
						order_sn: this.payForm.ordersn

					})
					if (status == 1) {
						this.$util.msg('支付成功')
						this.clearInterval()
						setTimeout(() => {
							this.popupShow = false
							// this.$util.on(url)
							this.$emit('success', {
								payWay: this.payWay,
								orderData: this.orderData,
								payForm: this.payForm,
								url
							})
						}, 1000)
					}
				} catch (e) {
					this.clearInterval()
				}
			},
			clearInterval() {
				if (this.paystatusTimer) {
					clearInterval(this.paystatusTimer)
					this.paystatusTimer = null
				}
			},
			handelPasswordInputOk(e) {
				this.showPassInput = false
				this.payForm.trade_password = e
				this.pay()
			},
			handelScanpyQrcodeClose() {
				this.clearInterval()
			},
			handelAlipayUserOk({
				url
			}) {
				this.clearInterval()
this.payjunPopupShow = false
				this.ordersn = ''
				this.order_id = ''
				setTimeout(() => {
					this.$util.on(url)
				}, 1000)
			},
		}
	}
</script>
<style scoped lang="scss" scoped>
	.popup-box {
		display: flex;
		flex-direction: column;
		height: 100%;
	}

	.scroll-Y {
		flex: 1;
		overflow: hidden;
	}

	.popup-title {
		height: 106rpx;
		display: flex;
		align-items: center;
		justify-content: center;
		font-size: 32rpx;
		font-weight: bold;
	}

	.popup-footer {
		padding-top: 20rpx;
		padding-bottom: 20rpx;

		::v-deep {
			.comp-box {
				width: auto !important;
			}
		}

		.ok-btn {
			display: flex;
			align-items: center;
			justify-content: center;
			height: 90rpx;
			overflow: hidden;
			width: 90%;
			margin: 0 auto;
			border-radius: 10rpx;
		}
	}
</style>