<template>
	<view>
		<u-popup v-model="popupShow" :custom-style="customStyle" mode="center" :z-index="9999" safe-area-inset-bottom
			:mask-custom-style="{background: 'rgba(0, 0, 0, 0.4)'}" :border-radius="20" :closeable="false"
			@close="close" @open="open">
			<view class="popup-wrap">
				<view class="popup-title">
					重要提示
				</view>
				<view class="roll-box">
					<scroll-view scroll-y="true" class="scroll-Y">
						<view class="title"><u-icon name="volume-up" color="#FE5957" size="40" />充值提醒</view>
						<u-parse :html="content"></u-parse>
					</scroll-view>
				</view>
				<view class="ok-button" @click="popupShow=false">我知道了</view>
			</view>
		</u-popup>
	</view>
</template>

<script>
	export default {
		components: {

		},
		props: {
			value: {
				type: Boolean,
				default: false,
			},
			content: {
				type: [String, undefined, null],
				default: ''
			}
		},
		data() {
			return {};
		},
		computed: {
			customStyle() {
				const re = {}
				// #ifndef H5
				re.bottom = '110rpx'
				// #endif
				return re
			},
			popupShow: {
				get() {
					return this.value
				},
				set(val) {
					this.$emit('input', val)
				},
			}
		},
		watch: {

		},
		created() {

		},
		mounted() {

		},
		methods: {
			close() {

			},
			open() {

			}
		},
	};
</script>

<style scoped lang="scss" scoped>
	.popup-wrap {
		padding: 20rpx;
		width: 600rpx;

		.popup-title {
			position: relative;
			font-size: 40rpx;
			font-weight: bold;
			text-align: center;
		}
	}

	.roll-box {
		margin-top: 36rpx;
		border-radius: 20rpx;
		background-color: #F9F9FB;
		padding: 20rpx;

		.scroll-Y {
			max-height: 540rpx;

			.title {
				display: flex;
				gap: 10rpx;
				font-weight: 700;
				margin-bottom: 30rpx;
			}
		}
	}

	.ok-button {
		height: 68rpx;
		display: flex;
		align-items: center;
		justify-content: center;
		background-color: #F40000;
		border-radius: 40rpx;
		color: #fff;
		font-size: 30rpx;
		margin-top: 30rpx;
	}
</style>