<template>
	<view class="pay-way mt-20">
		<u-cell-group :border="false" title="支付方式">
			<u-cell-item :arrow="false" v-for="(item,index) in payList" :key="index"
				@click="handelChangePayWay(item,index)" :border-bottom="payList.length-1 ===index ?false:true">
				<template #title>
					<view class="title-box">
						<u-image :src="$util.img(item.img)" width="60rpx" height="60rpx" border-radius="50%" />
						<view class="right">
							<view class="pay-title">
								{{item.title}}
							</view>
							<view class="pay-tips" v-if="item.tips">
								{{ item.tips }}
							</view>
						</view>

					</view>
				</template>
				<view class="content-box">
					<view>
						<text class="balance" v-if="item.name=='balance'">余额：{{balance}}元</text>
						<text class="fee" v-else>{{item.fee ? `手续费：${item.fee}`:'免手续费'}}</text>
					</view>
					<view>
						<text style="color: #fa3534;" class="iconfont"
							:class="{'icon-danxuanxuanzhong':selectedPayIndex == index,'icon-danxuan':selectedPayIndex != index}"></text>
					</view>
				</view>
			</u-cell-item>
		</u-cell-group>
	</view>
</template>

<script>
	export default {
		name: 'pay-way',
		components: {},
		inject: [],
		props: {
			type: {
				type: String,
				required: true,
				default: ''
			},
			levelId: {
				type: Number,
				default: 0,
			},
			money: {
				type: [Number, String],
				default: 0
			},
			orderSn: {
				type: String,
				default: '',
			},
		},
		data() {
			return {
				selectedPayIndex: -1,
				payList: []
			}
		},
		computed: {
			balance() {
				let find = this.payList.find((item) => item.name == 'balance')
				return find ? Number(find.money) : 0
			},
			queryForm() {
				return {
					type: this.type,
					level_id: this.levelId,
					money: this.money,
					order_sn: this.orderSn
				}
			}
		},
		watch: {
			queryForm: {
				handler() {
					this.fetchData()
				},
				deep: true,
				immediate: true,
			}
		},
		created() {},
		mounted() {},
		methods: {
			handelChangePayWay(row, idx) {
				this.selectedPayIndex = idx
				this.$emit('change', row)
			},
			async fetchData() {
				const {
					pay_list
				} = await this.$u.api.payList(this.queryForm)
				this.payList = pay_list
				if (pay_list.length) {
					this.selectedPayIndex = 0
					this.$emit('change', pay_list[0])
				}
			}
		}
	}
</script>
<style scoped lang="scss" scoped>
	.pay-way {
		::v-deep {
			.u-cell-item-box {
				border-radius: 30rpx;
			}
		}

		.title-box {
			display: flex;
			align-items: center;
			gap: 20rpx;

			.right {
				display: flex;
				flex-direction: column;
				gap: 10rpx;
				line-height: 38rpx;
				align-items: flex-start;

				.pay-title {
					position: relative;
				}

				.pay-tips {
					background-color: #e93323;
					color: #fff;
					font-size: 24rpx;
					padding: 2rpx 10rpx;
					border-radius: 6rpx;
				}
			}

		}

		.content-box {
			display: flex;
			justify-content: flex-end;
			gap: 30rpx;

			.fee {
				color: #fa3534;
			}
		}
	}
</style>